// ==================== LOGIN BACKGROUND ====================
let LOGIN_BACKGROUNDS=[{type:'gradient',value:'linear-gradient(135deg,#0f172a,#1e293b,#0f172a)'},{type:'gradient',value:'linear-gradient(135deg,#1e3a5f,#0f2a4a,#1a1a2e)'},{type:'gradient',value:'linear-gradient(135deg,#0f2027,#203a43,#2c5364)'},{type:'gradient',value:'linear-gradient(135deg,#1a1a2e,#16213e,#0f3460)'},{type:'gradient',value:'linear-gradient(135deg,#0f0c29,#302b63,#24243e)'},{type:'image',value:'https://images.unsplash.com/photo-1558618666-fcd25c85f82e?w=1200'},{type:'image',value:'https://images.unsplash.com/photo-1497366216548-37526070297c?w=1200'},{type:'image',value:'https://images.unsplash.com/photo-1486406146926-c627a92ad1ab?w=1200'}];let cbg=0,bgi=null;
function ilb(){const sc=localStorage.getItem('custom_login_bgs');if(sc){try{JSON.parse(sc).forEach(bg=>{if(!LOGIN_BACKGROUNDS.find(b=>b.value===bg))LOGIN_BACKGROUNDS.push({type:'image',value:bg,custom:true});});}catch(e){}}const sb=localStorage.getItem('login_bg_index');if(sb!==null)cbg=parseInt(sb);alb();sbs();rbd();}
function alb(){const bg=LOGIN_BACKGROUNDS[cbg];const s=document.getElementById('loginScreen');const ss=document.getElementById('loginBgSlideshow');if(bg.type==='gradient'){s.style.background=bg.value;ss.style.backgroundImage='none';}else{s.style.background='#1a1a2e';ss.style.backgroundImage=`url(${bg.value})`;}document.querySelectorAll('.login-bg-dot').forEach((d,i)=>d.classList.toggle('active',i===cbg));}
function sbs(){if(bgi)clearInterval(bgi);bgi=setInterval(()=>{cbg=(cbg+1)%LOGIN_BACKGROUNDS.length;localStorage.setItem('login_bg_index',cbg);alb();},8000);}
function rbd(){document.getElementById('loginBgControls').innerHTML=LOGIN_BACKGROUNDS.map((_,i)=>`<div class="login-bg-dot ${i===cbg?'active':''}" onclick="slb(${i})"></div>`).join('');}
function slb(i){cbg=i;localStorage.setItem('login_bg_index',i);alb();if(bgi)clearInterval(bgi);sbs();}
function acb(e){const f=e.target.files[0];if(!f||f.size>2*1024*1024)return;const r=new FileReader();r.onload=ev=>{LOGIN_BACKGROUNDS.push({type:'image',value:ev.target.result,custom:true});cbg=LOGIN_BACKGROUNDS.length-1;localStorage.setItem('login_bg_index',cbg);localStorage.setItem('custom_login_bgs',JSON.stringify(LOGIN_BACKGROUNDS.filter(b=>b.custom).map(b=>b.value)));alb();rbd();showToast('Custom background added!','success');};r.readAsDataURL(f);}
function rb2(){LOGIN_BACKGROUNDS=LOGIN_BACKGROUNDS.filter(b=>!b.custom);localStorage.removeItem('custom_login_bgs');cbg=0;localStorage.setItem('login_bg_index',0);alb();rbd();showToast('Reset!','success');}

