// ==================== FIREBASE INTEGRATION ====================
let currentDB = null;          // in‑memory copy of the whole database
let dbListener = null;         // Firebase listener reference
let externalUpdate = false;    // prevent re‑render loops

// Start listening to Firebase and keep currentDB up‑to‑date
function initFirebaseDB() {
  if (!window.firebaseDB) return;

  const dbRef = window.firebaseRef(window.firebaseDB, 'currentDB');

  dbListener = window.firebaseOnValue(dbRef, (snapshot) => {
    const data = snapshot.val();
    if (data) {
      // If the change didn't come from this device, set the flag
      if (currentDB && !externalUpdate) {
        externalUpdate = true;
      } else {
        externalUpdate = false;
      }
      currentDB = data;
      // Refresh the visible page if it's one that shows live data
      refreshCurrentPage();
    } else {
      // First time: create empty database structure
      currentDB = {
        products: [],
        purchases: [],
        sales: [],
        expenses: [],
        customers: [],
        suppliers: [],
        creditSales: [],
        drafts: []
      };
      saveFirebaseDB(currentDB);
    }
  });
}

// Save the whole database to Firebase (called after every write)
function saveFirebaseDB(db) {
  if (!window.firebaseDB) return;
  // Prevent listener from re‑triggering refresh on this device
  externalUpdate = true;
  window.firebaseSet(window.firebaseRef(window.firebaseDB, 'currentDB'), db);
}

// Helper to re‑render whatever page is currently visible
function refreshCurrentPage() {
  if (!externalUpdate) return; // only refresh if change came from another device
  const activePage = document.querySelector('.nav-item.active');
  if (!activePage) return;
  const pageName = activePage.dataset.page;
  // Re‑render the most common live pages (others will refresh on next manual navigation)
  if (pageName === 'dashboard') renderDashboard(document.getElementById('mainContent'));
  else if (pageName === 'products') { renderProducts(document.getElementById('mainContent')); renderProductTable(); }
  else if (pageName === 'sale') renderSaleHistory();
  else if (pageName === 'purchase') renderPurHistory();
  // You can add more pages as needed.
  externalUpdate = false;
}

// ==================== OVERRIDE CORE DATA FUNCTIONS ====================
function getDB() {
  // If Firebase hasn't loaded yet or we are offline, fallback to localStorage
  if (!currentDB) {
    const r = localStorage.getItem(DB_KEY);
    return r ? JSON.parse(r) : {
      products: [], purchases: [], sales: [], expenses: [],
      customers: [], suppliers: [], creditSales: [], drafts: []
    };
  }
  return currentDB;
}

function saveDB(db) {
  // Always update our in‑memory copy
  currentDB = db;
  // Save to Firebase (real‑time cloud)
  if (window.firebaseDB) {
    saveFirebaseDB(db);
  }
  // Also keep localStorage updated for offline fallback
  localStorage.setItem(DB_KEY, JSON.stringify(db));
  updateStorageInfo();
}

function updateStorageInfo(){const d=getDB();const kb=(new Blob([JSON.stringify(d)]).size/1024).toFixed(1);const el=document.getElementById('storage-usage');if(el)el.textContent='📊 '+kb+' KB';const bd=document.getElementById('branding-date');if(bd)bd.textContent=new Date().toLocaleDateString('en-IN',{weekday:'short',day:'numeric',month:'short',year:'numeric'});}
function getBranding(){const r=localStorage.getItem(BRANDING_KEY);const d={companyName:'WishMe Enterprise',tagline:'Inventory, Sales & Business Management Suite',owner:'',phone:'',email:'',address:'',website:'',bankName:'',bankAccount:'',bankBranch:'',bankRouting:'',logo:null,themeColor:'#4f46e5'};if(!r)return d;try{return{...d,...JSON.parse(r)};}catch(e){return d;}}
function saveBranding(b){localStorage.setItem(BRANDING_KEY,JSON.stringify(b));applyBranding(b);}
function applyBranding(b){document.getElementById('branding-company-name').textContent=b.companyName;document.querySelector('.branding-tagline').textContent=b.tagline;const lc=document.getElementById('branding-logo-container');lc.innerHTML=b.logo?`<img src="${b.logo}" class="branding-logo">`:`<div class="branding-logo-placeholder">${b.companyName.charAt(0)}</div>`;document.getElementById('sidebar-company-name').textContent=b.companyName;document.getElementById('footer-company').textContent=b.companyName;const slc=document.getElementById('sidebar-logo-container');slc.innerHTML=b.logo?`<img src="${b.logo}" class="mini-logo">`:`<div class="mini-logo-placeholder">${b.companyName.charAt(0)}</div>`;document.title=b.companyName+' - Suite';document.documentElement.style.setProperty('--primary',b.themeColor);const ll=document.getElementById('loginLogoDisplay');if(ll)ll.innerHTML=b.logo?`<img src="${b.logo}" style="width:72px;height:72px;border-radius:18px;">`:'🏢';}
function adjustColor(h,a){const n=parseInt(h.replace('#',''),16);return '#'+(0x1000000+Math.min(255,Math.max(0,(n>>16)+a))*0x10000+Math.min(255,Math.max(0,((n>>8)&0xFF)+a))*0x100+Math.min(255,Math.max(0,(n&0xFF)+a))).toString(16).slice(1);}
function saveSession(){if(currentUser){const u=getUsers();localStorage.setItem('current_session',JSON.stringify({key:currentUser.key,pass:u[currentUser.key].pass}));}}
function clearSession(){localStorage.removeItem('current_session');}
function checkExistingSession(){const s=localStorage.getItem('current_session');if(s){try{const se=JSON.parse(s);const u=getUsers();if(u[se.key]&&u[se.key].pass===se.pass){currentUser={key:se.key,...u[se.key]};document.getElementById('loginScreen').style.display='none';document.getElementById('appLayout').style.display='block';document.getElementById('currentUserName').textContent=currentUser.name;const re=document.getElementById('currentUserRole');re.textContent=currentUser.role==='admin'?'Admin':'Staff';re.className='user-role-tag '+(currentUser.role==='admin'?'role-admin':'role-staff');document.querySelectorAll('.admin-menu').forEach(el=>el.style.display=currentUser.role==='admin'?'':'none');applyBranding(getBranding());updateStorageInfo();navigateTo('dashboard');return true;}}catch(e){}}return false;}
function doLogin(){const k=document.getElementById('loginUser').value;const p=document.getElementById('loginPass').value;const err=document.getElementById('loginError');const u=getUsers();if(!k||!u[k]){err.textContent='Select a user.';err.style.display='block';return;}if(u[k].pass!==p){err.textContent='Wrong password!';err.style.display='block';return;}err.style.display='none';currentUser={key:k,...u[k]};saveSession();document.getElementById('loginScreen').style.display='none';document.getElementById('appLayout').style.display='block';document.getElementById('currentUserName').textContent=currentUser.name;const re=document.getElementById('currentUserRole');re.textContent=currentUser.role==='admin'?'Admin':'Staff';re.className='user-role-tag '+(currentUser.role==='admin'?'role-admin':'role-staff');document.querySelectorAll('.admin-menu').forEach(el=>el.style.display=currentUser.role==='admin'?'':'none');applyBranding(getBranding());updateStorageInfo();navigateTo('dashboard');showToast(`Welcome, ${currentUser.name}!`,'success');}
