function navigateTo(p){document.querySelectorAll('.nav-item').forEach(n=>n.classList.remove('active'));const t=document.querySelector(`.nav-item[data-page="${p}"]`);if(t)t.classList.add('active');const mc=document.getElementById('mainContent');const ia=currentUser?.role==='admin';switch(p){case'dashboard':renderDashboard(mc);break;case'products':ia?renderProducts(mc):accessDenied(mc);break;case'bulk-import':ia?renderBulkImport(mc):accessDenied(mc);break;case'customers':ia?renderCustomers(mc):accessDenied(mc);break;case'suppliers':ia?renderSuppliers(mc):accessDenied(mc);break;case'bulk-customers':ia?renderBulkCustomers(mc):accessDenied(mc);break;case'bulk-suppliers':ia?renderBulkSuppliers(mc):accessDenied(mc);break;case'purchase':renderPurchase(mc);break;case'sale':renderSale(mc);break;case'drafts':renderDrafts(mc);break;case'expenses':ia?renderExpenses(mc):accessDenied(mc);break;case'credit-sales':ia?renderCreditSales(mc):accessDenied(mc);break;case'cash-book':ia?renderCashBook(mc):accessDenied(mc);break;case'stock':ia?renderStock(mc):accessDenied(mc);break;case'profit':ia?renderProfit(mc):accessDenied(mc);break;case'inventory-aging':ia?renderInventoryAging(mc):accessDenied(mc);break;case'top-products':ia?renderTopProducts(mc):accessDenied(mc);break;case'expiry':ia?renderExpiry(mc):accessDenied(mc);break;case'branding':ia?renderBranding(mc):accessDenied(mc);break;case'users':ia?renderUsers(mc):accessDenied(mc);break;case'storage-settings':ia?renderStorageSettings(mc):accessDenied(mc);break;case'settings':ia?renderSettings(mc):accessDenied(mc);break;case'activity':renderActivity(mc);break;case'change-password':renderChangePassword(mc);break;}}
function accessDenied(mc){mc.innerHTML='<div style="text-align:center;padding:60px;"><h3>🔒 Access Denied</h3></div>';}
function getStock(pid){const db=getDB();return db.purchases.filter(p=>p.productId===pid).reduce((s,p)=>s+(p.qty||0),0)-db.sales.filter(s=>s.productId===pid&&!s.isReturn).reduce((s,x)=>s+(x.qty||0),0)+db.sales.filter(s=>s.productId===pid&&s.isReturn).reduce((s,x)=>s+(x.qty||0),0);}
function fmtBDT(v){return '৳'+(parseFloat(v)||0).toLocaleString('en-IN',{minimumFractionDigits:2});}
function fmtDate(d){return d?new Date(d).toLocaleDateString('en-IN',{day:'2-digit',month:'short',year:'numeric'}):'-';}
function genId(){return 'id_'+Date.now()+'_'+Math.random().toString(36).substr(2,6);}
function downloadFile(c,f,m){const b=new Blob([c],{type:m+';charset=utf-8;'});const u=URL.createObjectURL(b);const a=document.createElement('a');a.href=u;a.download=f;document.body.appendChild(a);a.click();document.body.removeChild(a);URL.revokeObjectURL(u);}
function downloadCSV(c,f){downloadFile(c,f,'text/csv');}
let tempPhotoData=null;
function handlePhotoUpload(e){const f=e.target.files[0];if(!f)return;const r=new FileReader();r.onload=ev=>{tempPhotoData=ev.target.result;const img=document.getElementById('photo-preview-img');if(img){img.src=tempPhotoData;img.style.display='block';}const ph=document.getElementById('photo-placeholder');if(ph)ph.style.display='none';const rb=document.getElementById('remove-photo-btn');if(rb)rb.style.display='inline-flex';};r.readAsDataURL(f);}
function removePhoto(){tempPhotoData=null;const img=document.getElementById('photo-preview-img');if(img)img.style.display='none';const ph=document.getElementById('photo-placeholder');if(ph)ph.style.display='block';const rb=document.getElementById('remove-photo-btn');if(rb)rb.style.display='none';}
