function getNextInvoiceNumber(){let s=parseInt(localStorage.getItem('invoice_serial')||'0');const db=getDB();if(s===0&&db.sales.length>0)s=db.sales.length;s++;localStorage.setItem('invoice_serial',s.toString());const p=localStorage.getItem('invoice_prefix')||'INV';const y=localStorage.getItem('invoice_use_year')!=='false';return y?`${p}-${new Date().getFullYear()}-${s.toString().padStart(4,'0')}`:`${p}-${s.toString().padStart(4,'0')}`;}
function getCurrentInvoiceSerial(){let s=parseInt(localStorage.getItem('invoice_serial')||'0');if(s===0){const db=getDB();s=db.sales.length;}return s;}

