function showForgotPassword(){const u=getUsers();let ul='';Object.entries(u).forEach(([k,v])=>{ul+=`<option value="${k}">${v.name} (${v.role})</option>`;});const m=document.createElement('div');m.id='fpm';m.style.cssText='position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.6);z-index:999;display:flex;justify-content:center;align-items:center;';m.innerHTML=`<div style="background:var(--card);padding:30px;border-radius:var(--radius);max-width:400px;width:90%;"><h3>🔑 Reset</h3><select id="ru" style="width:100%;padding:10px;border:2px solid var(--border);border-radius:8px;margin:12px 0;"><option value="">-- Select --</option>${ul}</select><div id="rq" style="display:none;"><p id="sq" style="font-weight:600;color:var(--primary);margin-bottom:8px;"></p><input type="text" id="sa" placeholder="Answer" style="width:100%;padding:10px;border:2px solid var(--border);border-radius:8px;margin-bottom:8px;"><input type="password" id="np" placeholder="New password (6+)" style="width:100%;padding:10px;border:2px solid var(--border);border-radius:8px;margin-bottom:8px;"><button class="btn btn-primary btn-block" onclick="resetPassword()">🔐 Reset</button></div><button class="btn btn-ghost btn-sm" onclick="document.getElementById('fpm').remove()">❌ Cancel</button><div id="rm"></div></div>`;document.body.appendChild(m);setTimeout(()=>{document.getElementById('ru').addEventListener('change',function(){if(this.value){document.getElementById('rq').style.display='block';document.getElementById('sq').textContent='Company name? (Hint: '+getBranding().companyName+')';}else{document.getElementById('rq').style.display='none';}});},100);}
function resetPassword(){const k=document.getElementById('ru').value;const a=document.getElementById('sa').value.trim();const np=document.getElementById('np').value;const rm=document.getElementById('rm');if(!k)return;if(a.toLowerCase()!==getBranding().companyName.toLowerCase()){rm.innerHTML='<span style="color:var(--danger);">❌ Wrong!</span>';return;}if(!np||np.length<6)return;const u=getUsers();u[k].pass=np;saveUsers(u);rm.innerHTML='<span style="color:var(--success);">✅ Done!</span>';setTimeout(()=>{document.getElementById('fpm').remove();},1500);}

// ==================== DASHBOARD ====================
function renderDashboard(mc){const db=getDB();let sv=0,lc=0;db.products.forEach(p=>{const s=getStock(p.id);sv+=s*(p.buyPrice||0);if(s<(p.minStock||10))lc++;});const today=new Date().toISOString().split('T')[0];const ts=db.sales.filter(s=>s.date===today&&!s.isReturn).reduce((s,x)=>s+x.qty,0);let tp=0;db.sales.filter(s=>s.date===today&&!s.isReturn).forEach(s=>{const pr=db.products.find(p=>p.id===s.productId);if(pr)tp+=s.qty*((pr.sellPrice||0)-(pr.buyPrice||0));});const ex=db.expenses||[];const tde=ex.filter(e=>e.date===today).reduce((s,e)=>s+(parseFloat(e.amount)||0),0);const dt=(db.creditSales||[]).filter(c=>c.status==='pending').reduce((s,c)=>s+(parseFloat(c.dueAmount)||0),0);const now=new Date();const mr=Array(6).fill(0),ml=[];for(let i=5;i>=0;i--){const d=new Date(now.getFullYear(),now.getMonth()-i,1);ml.push(d.toLocaleDateString('en-IN',{month:'short',year:'2-digit'}));const ms=d.toISOString().substring(0,7);db.sales.filter(s=>!s.isReturn).forEach(s=>{if(s.date?.substring(0,7)===ms){const p=db.products.find(x=>x.id===s.productId);mr[5-i]+=s.qty*(p?.sellPrice||0);}});}
mc.innerHTML=`<div class="page-header"><div><h2>📊 Dashboard</h2><p>Welcome, ${currentUser.name}!</p></div><div style="position:relative;"><input type="text" class="global-search" id="globalSearch" placeholder="🔍 Search products..."><div id="searchResultsContainer"></div></div></div><div class="stats-grid"><div class="stat-card primary"><div class="stat-icon">📦</div><div class="stat-value">${db.products.length}</div><div class="stat-label">Products</div></div><div class="stat-card success"><div class="stat-icon">💎</div><div class="stat-value">${fmtBDT(sv)}</div><div class="stat-label">Stock Value</div></div><div class="stat-card warning"><div class="stat-icon">⚠️</div><div class="stat-value">${lc}</div><div class="stat-label">Low Stock</div></div><div class="stat-card"><div class="stat-icon">📊</div><div class="stat-value">${ts}</div><div class="stat-label">Sold Today</div></div><div class="stat-card success"><div class="stat-icon">💰</div><div class="stat-value">${fmtBDT(tp)}</div><div class="stat-label">Gross Profit</div></div><div class="stat-card danger"><div class="stat-icon">💸</div><div class="stat-value">${fmtBDT(tde)}</div><div class="stat-label">Expenses Today</div></div><div class="stat-card ${tp-tde>=0?'success':'danger'}"><div class="stat-icon">🏦</div><div class="stat-value">${fmtBDT(tp-tde)}</div><div class="stat-label">Net Profit</div></div><div class="stat-card info"><div class="stat-icon">📋</div><div class="stat-value">${fmtBDT(dt)}</div><div class="stat-label">Due Amount</div></div></div><div class="chart-row"><div class="card"><h3>📈 Monthly Revenue</h3><div class="chart-container"><canvas id="revenueChart"></canvas></div></div><div class="card"><h3>📊 Quick Stats</h3><div style="line-height:2.5;">👥 Customers: <strong>${(db.customers||[]).length}</strong><br>🏭 Suppliers: <strong>${(db.suppliers||[]).length}</strong><br>📋 Pending Dues: <strong>${fmtBDT(dt)}</strong><br>💸 Total Expenses: <strong>${fmtBDT(ex.reduce((s,e)=>s+(parseFloat(e.amount)||0),0))}</strong></div></div></div>`;setTimeout(()=>{const c1=document.getElementById('revenueChart');if(c1)new Chart(c1,{type:'bar',data:{labels:ml,datasets:[{label:'Revenue',data:mr,backgroundColor:'#4f46e5',borderRadius:8}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}}}});},200);}

