document.addEventListener('input',function(e){if(e.target.id==='globalSearch'&&currentUser){var q=e.target.value.trim();var container=document.getElementById('searchResultsContainer');if(container)container.innerHTML='';if(q.length<2)return;var db=getDB();var results=db.products.filter(function(p){return p.name.toLowerCase().indexOf(q.toLowerCase())>-1||(p.barcode&&p.barcode.indexOf(q)>-1)||(p.company&&p.company.toLowerCase().indexOf(q.toLowerCase())>-1);});if(results.length>0&&container){var html='<div style="position:absolute;top:38px;right:0;background:var(--card);border:1px solid var(--border);border-radius:8px;box-shadow:0 10px 30px rgba(0,0,0,0.2);z-index:999;max-height:300px;overflow-y:auto;min-width:300px;">';for(var i=0;i<Math.min(results.length,8);i++){var p=results[i];var stock=getStock(p.id);html+='<div style="padding:10px 14px;cursor:pointer;border-bottom:1px solid var(--border-light);" onmouseover="this.style.background=\'var(--card-hover)\'" onmouseout="this.style.background=\'\'" onclick="navigateTo(\'products\');setTimeout(function(){var sb=document.getElementById(\'search-product\');if(sb)sb.value=\''+p.name.replace(/'/g,"\\'")+'\';renderProductTable();},300);this.parentElement.remove();"><strong>'+p.name+'</strong><br><small>📦 Stock: '+stock+' | '+fmtBDT(p.sellPrice)+'</small></div>';}html+='</div>';container.innerHTML=html;}}});
document.addEventListener('click',function(e){if(e.target.id!=='globalSearch'){var c=document.getElementById('searchResultsContainer');if(c)c.innerHTML='';}});
document.addEventListener('keydown',function(e){if(e.key==='/'&&document.activeElement===document.body&&currentUser){e.preventDefault();var gs=document.getElementById('globalSearch');if(gs)gs.focus();}});

// ==================== PRODUCTS ====================
function renderProducts(mc){const db=getDB();mc.innerHTML=`<div class="page-header"><h2>🏷️ Products</h2><button class="btn btn-primary" onclick="document.getElementById('productForm').style.display='block'">➕ Add</button></div><div id="productForm" style="display:none;" class="card"><h3>➕ Add Product</h3><div class="form-grid"><div class="form-group"><label>Name *</label><input type="text" id="pName"></div><div class="form-group"><label>Barcode</label><input type="text" id="pBarcode"></div><div class="form-group"><label>Company</label><input type="text" id="pComp"></div><div class="form-group"><label>Category</label><input type="text" id="pCat"></div><div class="form-group"><label>Unit</label><select id="pUnit"><option>pcs</option><option>kg</option><option>box</option><option>pack</option><option>liter</option></select></div><div class="form-group"><label>Buy Price *</label><input type="number" id="pBuy" step="0.01"></div><div class="form-group"><label>Sell Price *</label><input type="number" id="pSell" step="0.01"></div><div class="form-group"><label>Min Stock</label><input type="number" id="pMin" value="10"></div><div class="form-group"><label>Expiry</label><input type="date" id="pExp"></div><div class="form-group"><label>Conversion</label><input type="text" id="pConversion"></div><div class="form-group"><label>Photo</label><div class="photo-upload-area" onclick="document.getElementById('photo-input').click()"><span id="photo-placeholder">📸 Click</span><img id="photo-preview-img" style="display:none;max-width:100px;"><input type="file" id="photo-input" accept="image/*" style="display:none;" onchange="handlePhotoUpload(event)"></div></div></div><button class="btn btn-primary" onclick="addProduct()">💾 Save</button></div><div class="card"><h3>Products (${db.products.length})</h3><input type="text" id="search-product" placeholder="🔍 Search..." oninput="renderProductTable()" style="padding:8px;border:2px solid var(--border);border-radius:6px;margin-bottom:10px;width:100%;"><div class="table-container"><table><thead><tr><th>Product</th><th>Company</th><th>Buy</th><th>Sell</th><th>Stock</th><th>Actions</th></tr></thead><tbody id="productTableBody"></tbody></table></div></div>`;renderProductTable();}
function renderProductTable(){const db=getDB();const s=(document.getElementById('search-product')?.value||'').toLowerCase();let data=db.products;if(s)data=data.filter(p=>p.name.toLowerCase().includes(s)||(p.barcode&&p.barcode.includes(s)));document.getElementById('productTableBody').innerHTML=data.map(p=>{const stk=getStock(p.id);const ph=p.photo?`<span class="product-photo-wrap" onclick="showImageModal('${p.photo}')"><img src="${p.photo}" class="product-thumb"></span>`:'';return`<tr><td>${ph} <strong>${p.name}</strong>${p.conversion?`<br><small>${p.conversion}</small>`:''}</td><td>${p.company||'-'}</td><td>${fmtBDT(p.buyPrice)}</td><td>${fmtBDT(p.sellPrice)}</td><td><span class="badge ${stk<=(p.minStock||10)?(stk===0?'badge-danger':'badge-warning'):'badge-success'}">${stk}</span></td><td><button class="btn btn-info btn-xs" onclick="editProduct('${p.id}')">✏️</button> <button class="btn btn-warning btn-xs" onclick="cloneProduct('${p.id}')">📋</button> <button class="btn btn-danger btn-xs" onclick="deleteProduct('${p.id}')">🗑️</button></td></tr>`;}).join('')||'<tr><td colspan="6">No products. </td></tr>';}
function addProduct(){const n=document.getElementById('pName').value.trim();const bp=parseFloat(document.getElementById('pBuy').value);const sp=parseFloat(document.getElementById('pSell').value);if(!n||isNaN(bp)||isNaN(sp)){showToast('Fill Name, Buy, Sell!','error');return;}const db=getDB();db.products.push({id:genId(),name:n,barcode:document.getElementById('pBarcode').value,company:document.getElementById('pComp').value,category:document.getElementById('pCat').value,unit:document.getElementById('pUnit').value,buyPrice:bp,sellPrice:sp,minStock:parseInt(document.getElementById('pMin').value)||10,expiryDate:document.getElementById('pExp').value,conversion:document.getElementById('pConversion').value,photo:tempPhotoData,createdAt:new Date().toISOString()});saveDB(db);removePhoto();document.getElementById('productForm').style.display='none';renderProducts(document.getElementById('mainContent'));showToast('Added!','success');}
function deleteProduct(id){if(!confirm('Delete?'))return;const db=getDB();db.products=db.products.filter(p=>p.id!==id);saveDB(db);renderProducts(document.getElementById('mainContent'));showToast('Deleted.','warning');}
function editProduct(id){const db=getDB();const p=db.products.find(x=>x.id===id);if(!p)return;const nn=prompt('Name:',p.name);if(!nn)return;const bp=parseFloat(prompt('Buy:',p.buyPrice));const sp=parseFloat(prompt('Sell:',p.sellPrice));if(isNaN(bp)||isNaN(sp))return;p.name=nn;p.buyPrice=bp;p.sellPrice=sp;saveDB(db);renderProducts(document.getElementById('mainContent'));showToast('Updated!','success');}
function cloneProduct(id){const db=getDB();const oi=db.products.findIndex(x=>x.id===id);if(oi===-1)return;const p=db.products[oi];db.products.splice(oi+1,0,{...p,id:genId(),name:p.name+' (Copy)',barcode:'',createdAt:new Date().toISOString()});saveDB(db);renderProducts(document.getElementById('mainContent'));showToast('Cloned!','success');}

// ==================== BULK IMPORT ====================
function renderBulkImport(mc){mc.innerHTML=`<div class="page-header"><h2>📥 Bulk Import Products</h2></div><div class="card"><textarea id="pasteData" rows="8" style="width:100%;font-family:monospace;" placeholder="Name,Company,Category,Unit,Buy,Sell,Min,Conversion"></textarea><button class="btn btn-primary" onclick="bulkImport()">📋 Import</button> <button class="btn btn-outline" onclick="downloadCSV('\uFEFFName,Company,Category,Unit,BuyPrice,SellPrice,MinStock,Conversion','template.csv')">📥 Template</button></div>`;}
function bulkImport(){const t=document.getElementById('pasteData').value;const lines=t.split('\n').filter(l=>l.trim());const db=getDB();let c=0;for(let i=1;i<lines.length;i++){const v=lines[i].split(/[,;\t]/);if(v.length<3)continue;db.products.push({id:genId(),name:v[0]?.trim(),company:v[1]?.trim(),category:v[2]?.trim(),unit:v[3]?.trim()||'pcs',buyPrice:parseFloat(v[4])||0,sellPrice:parseFloat(v[5])||0,minStock:parseInt(v[6])||10,conversion:v[7]?.trim()||'',createdAt:new Date().toISOString()});c++;}saveDB(db);showToast(`${c} imported!`,'success');navigateTo('products');}

// ==================== CUSTOMERS (fixed) ====================
function renderCustomers(mc){const db=getDB();const cust=db.customers||[];mc.innerHTML=`<div class="page-header"><h2>👥 Customers</h2><div><button class="btn btn-primary" onclick="showAddCustomer()">➕ Add</button> <button class="btn btn-outline btn-sm" onclick="navigateTo('bulk-customers')" style="margin-left:8px;">📥 Bulk Import</button></div></div><div class="card"><div class="table-container"><table><thead><tr><th>Name</th><th>Phone</th><th>Address</th><th>Actions</th></tr></thead><tbody>${cust.map(c=>`<tr><td><strong>${c.name}</strong></td><td>${c.phone||'-'}</td><td>${c.address||'-'}</td><td><button class="btn btn-info btn-xs" onclick="editCustomer('${c.id}')">✏️</button> <button class="btn btn-danger btn-xs" onclick="deleteCustomer('${c.id}')">🗑️</button></td></tr>`).join('')||'<tr><td colspan="4">No customers.</td></tr>'}</tbody></table></div></div><div id="customerForm" style="display:none;" class="card"><h3>➕ Add Customer</h3><div class="form-grid"><div class="form-group"><label>Name *</label><input type="text" id="custName"></div><div class="form-group"><label>Phone</label><input type="text" id="custPhone"></div><div class="form-group"><label>Address</label><textarea id="custAddress"></textarea></div></div><button class="btn btn-primary" onclick="saveCustomer()">💾 Save</button><input type="hidden" id="custId"></div>`;}
function showAddCustomer(){document.getElementById('customerForm').style.display='block';document.getElementById('custId').value='';document.getElementById('custName').value='';document.getElementById('custPhone').value='';document.getElementById('custAddress').value='';}
function editCustomer(id){const c=getDB().customers.find(x=>x.id===id);if(!c)return;document.getElementById('customerForm').style.display='block';document.getElementById('custId').value=c.id;document.getElementById('custName').value=c.name;document.getElementById('custPhone').value=c.phone||'';document.getElementById('custAddress').value=c.address||'';}
function saveCustomer(){const id=document.getElementById('custId').value;const n=document.getElementById('custName').value.trim();if(!n){showToast('Enter name!','error');return;}const db=getDB();if(id){const c=db.customers.find(x=>x.id===id);if(c){c.name=n;c.phone=document.getElementById('custPhone').value;c.address=document.getElementById('custAddress').value;}}else{db.customers.push({id:genId(),name:n,phone:document.getElementById('custPhone').value,address:document.getElementById('custAddress').value,dueBalance:0,createdAt:new Date().toISOString()});}saveDB(db);document.getElementById('customerForm').style.display='none';renderCustomers(document.getElementById('mainContent'));showToast('Saved!','success');}
function deleteCustomer(id){if(!confirm('Delete?'))return;const db=getDB();db.customers=db.customers.filter(c=>c.id!==id);saveDB(db);renderCustomers(document.getElementById('mainContent'));showToast('Deleted.','warning');}

// ==================== SUPPLIERS ====================
function renderSuppliers(mc){const db=getDB();const supp=db.suppliers||[];mc.innerHTML=`<div class="page-header"><h2>🏭 Suppliers</h2><div><button class="btn btn-primary" onclick="showAddSupplier()">➕ Add</button> <button class="btn btn-outline btn-sm" onclick="navigateTo('bulk-suppliers')" style="margin-left:8px;">📥 Bulk Import</button></div></div><div class="card"><div class="table-container"><table><thead><tr><th>Name</th><th>Phone</th><th>Address</th><th>Actions</th></tr></thead><tbody>${supp.map(s=>`<tr><td><strong>${s.name}</strong></td><td>${s.phone||'-'}</td><td>${s.address||'-'}</td><td><button class="btn btn-info btn-xs" onclick="editSupplier('${s.id}')">✏️</button> <button class="btn btn-danger btn-xs" onclick="deleteSupplier('${s.id}')">🗑️</button></td></tr>`).join('')||'<tr><td colspan="4">No suppliers.</td></tr>'}</tbody></table></div></div><div id="supplierForm" style="display:none;" class="card"><h3>➕ Add Supplier</h3><div class="form-grid"><div class="form-group"><label>Name *</label><input type="text" id="suppName"></div><div class="form-group"><label>Phone</label><input type="text" id="suppPhone"></div><div class="form-group"><label>Address</label><textarea id="suppAddress"></textarea></div></div><button class="btn btn-primary" onclick="saveSupplier()">💾 Save</button><input type="hidden" id="suppId"></div>`;}
function showAddSupplier(){document.getElementById('supplierForm').style.display='block';document.getElementById('suppId').value='';document.getElementById('suppName').value='';document.getElementById('suppPhone').value='';document.getElementById('suppAddress').value='';}
function editSupplier(id){const s=getDB().suppliers.find(x=>x.id===id);if(!s)return;document.getElementById('supplierForm').style.display='block';document.getElementById('suppId').value=s.id;document.getElementById('suppName').value=s.name;document.getElementById('suppPhone').value=s.phone||'';document.getElementById('suppAddress').value=s.address||'';}
function saveSupplier(){const id=document.getElementById('suppId').value;const n=document.getElementById('suppName').value.trim();if(!n){showToast('Enter name!','error');return;}const db=getDB();if(id){const s=db.suppliers.find(x=>x.id===id);if(s){s.name=n;s.phone=document.getElementById('suppPhone').value;s.address=document.getElementById('suppAddress').value;}}else{db.suppliers.push({id:genId(),name:n,phone:document.getElementById('suppPhone').value,address:document.getElementById('suppAddress').value,createdAt:new Date().toISOString()});}saveDB(db);document.getElementById('supplierForm').style.display='none';renderSuppliers(document.getElementById('mainContent'));showToast('Saved!','success');}
function deleteSupplier(id){if(!confirm('Delete?'))return;const db=getDB();db.suppliers=db.suppliers.filter(s=>s.id!==id);saveDB(db);renderSuppliers(document.getElementById('mainContent'));showToast('Deleted.','warning');}

// ==================== BULK CUSTOMERS & SUPPLIERS ====================
function renderBulkCustomers(mc){mc.innerHTML=`<div class="page-header"><h2>📥 Bulk Import Customers</h2><p>← Back to <a href="#" onclick="navigateTo('customers')" style="color:var(--primary);">Customers</a></p></div><div class="info-box"><strong>Format:</strong> Name, Phone, Address (one per line)</div><div class="card"><textarea id="bulkCustData" rows="10" style="width:100%;font-family:monospace;" placeholder="Mr. Karim, 017XXXXXXXX, Gulshan Dhaka"></textarea><button class="btn btn-primary" onclick="bulkImportCustomers()" style="margin-top:10px;">📋 Import</button></div>`;}
function bulkImportCustomers(){const t=document.getElementById('bulkCustData').value;const lines=t.split('\n').filter(l=>l.trim());const db=getDB();let a=0;lines.forEach(line=>{const parts=line.split(/[,;\t]/);const n=(parts[0]||'').trim();if(!n)return;db.customers.push({id:genId(),name:n,phone:(parts[1]||'').trim(),address:(parts[2]||'').trim(),dueBalance:0,createdAt:new Date().toISOString()});a++;});saveDB(db);showToast(`${a} imported!`,'success');}
function renderBulkSuppliers(mc){mc.innerHTML=`<div class="page-header"><h2>📥 Bulk Import Suppliers</h2><p>← Back to <a href="#" onclick="navigateTo('suppliers')" style="color:var(--primary);">Suppliers</a></p></div><div class="info-box"><strong>Format:</strong> Name, Phone, Address (one per line)</div><div class="card"><textarea id="bulkSuppData" rows="10" style="width:100%;font-family:monospace;" placeholder="PRAN Foods, 017XXXXXXXX, Mirpur"></textarea><button class="btn btn-primary" onclick="bulkImportSuppliers()" style="margin-top:10px;">📋 Import</button></div>`;}
function bulkImportSuppliers(){const t=document.getElementById('bulkSuppData').value;const lines=t.split('\n').filter(l=>l.trim());const db=getDB();let a=0;lines.forEach(line=>{const parts=line.split(/[,;\t]/);const n=(parts[0]||'').trim();if(!n)return;db.suppliers.push({id:genId(),name:n,phone:(parts[1]||'').trim(),address:(parts[2]||'').trim(),createdAt:new Date().toISOString()});a++;});saveDB(db);showToast(`${a} imported!`,'success');}

// ==================== PURCHASE ====================
function renderPurchase(mc){const db=getDB();const so=(db.suppliers||[]).map(s=>`<option value="${s.name}">${s.name}</option>`).join('');mc.innerHTML=`<div class="page-header"><h2>📥 Add Purchase</h2></div><div class="card"><div class="form-grid"><div class="form-group"><label>Product *</label><select id="purProd"><option value="">-- Choose --</option>${db.products.map(p=>`<option value="${p.id}">${p.name} - ${getStock(p.id)} ${p.unit}</option>`).join('')}</select></div><div class="form-group"><label>Qty *</label><input type="number" id="purQty" min="1"></div><div class="form-group"><label>Date</label><input type="date" id="purDate" value="${new Date().toISOString().split('T')[0]}"></div><div class="form-group"><label>Supplier</label><input type="text" id="purSupp" list="suppList"><datalist id="suppList">${so}</datalist></div></div><button class="btn btn-success" onclick="addPurchase()">✅ Record</button></div><div class="card"><h3>History</h3><div class="date-filter">From:<input type="date" id="purFrom" onchange="renderPurHistory()"> To:<input type="date" id="purTo" onchange="renderPurHistory()"></div><div class="table-container" id="purHistory"></div></div>`;renderPurHistory();}
function addPurchase(){const pid=document.getElementById('purProd').value;const q=parseInt(document.getElementById('purQty').value);if(!pid||!q){showToast('Select product & qty!','error');return;}const db=getDB();const sp=document.getElementById('purSupp').value.trim();db.purchases.push({id:genId(),productId:pid,qty:q,date:document.getElementById('purDate').value,supplier:sp,user:currentUser.name,createdAt:new Date().toISOString()});if(sp&&!db.suppliers.find(s=>s.name===sp)){db.suppliers.push({id:genId(),name:sp,phone:'',address:'',createdAt:new Date().toISOString()});}saveDB(db);renderPurHistory();showToast('Purchased!','success');}
function renderPurHistory(){const db=getDB();const el=document.getElementById('purHistory');if(!el)return;const from=document.getElementById('purFrom')?.value||'';const to=document.getElementById('purTo')?.value||'';let data=[...db.purchases].filter(p=>{if(from&&p.date<from)return false;if(to&&p.date>to)return false;return true;}).reverse();el.innerHTML=`<table><thead><tr><th>Date</th><th>Product</th><th>Qty</th><th>Cost</th><th>Supplier</th></tr></thead><tbody>${data.map(p=>{const pr=db.products.find(x=>x.id===p.productId);return`<tr><td>${fmtDate(p.date)}</td><td><strong>${pr?.name||'?'}</strong></td><td>${p.qty}</td><td>${fmtBDT(p.qty*(pr?.buyPrice||0))}</td><td>${p.supplier||'-'}</td></tr>`;}).join('')||'<tr><td colspan="5">No purchases.</td></tr>'}</tbody></table>`;}

// ==================== SALE (with payment method) ====================
function renderSale(mc){const db=getDB();const co=(db.customers||[]).map(c=>`<option value="${c.id}">${c.name}</option>`).join('');mc.innerHTML=`<div class="page-header"><h2>📤 Record Sale</h2></div><div class="card"><div class="form-grid"><div class="form-group"><label>Product *</label><select id="saleProd"><option value="">-- Choose --</option>${db.products.map(p=>`<option value="${p.id}">${p.name} - ${getStock(p.id)} ${p.unit}</option>`).join('')}</select></div><div class="form-group"><label>Qty *</label><input type="number" id="saleQty" min="1"></div><div class="form-group"><label>Date</label><input type="date" id="saleDate" value="${new Date().toISOString().split('T')[0]}"></div><div class="form-group"><label>Customer</label><select id="saleCust"><option value="">-- Walk-in --</option>${co}</select></div><div class="form-group"><label>Payment Status</label><select id="salePaymentStatus"><option value="Paid">✅ Paid</option><option value="Unpaid">⏳ Unpaid</option><option value="Partial">💰 Partial</option></select></div><div class="form-group"><label>Payment Method</label><select id="salePaymentMethod"><option value="Cash">💵 Cash</option><option value="Mobile Banking">📱 Mobile Banking</option><option value="Card/Bank Transfer">💳 Card/Bank Transfer</option></select></div><div class="form-group"><label>Partial Amount (if Partial)</label><input type="number" id="salePartialAmount" step="0.01" placeholder="Amount paid"></div></div><button class="btn btn-danger" onclick="addSale()">💰 Record Sale</button> <button class="btn btn-outline" onclick="saveDraft()">💾 Draft</button> <button class="btn btn-primary" onclick="printCurrentSale()">🖨️ Print Invoice</button></div><div class="card"><h3>History</h3><div class="date-filter">From:<input type="date" id="saleFrom" onchange="renderSaleHistory()"> To:<input type="date" id="saleTo" onchange="renderSaleHistory()"></div><div class="table-container" id="saleHistory"></div></div>`;renderSaleHistory();}
function printCurrentSale(){const pid=document.getElementById('saleProd').value;const qty=parseInt(document.getElementById('saleQty').value);if(!pid||!qty){showToast('Select product & qty first!','error');return;}const db=getDB();const prod=db.products.find(p=>p.id===pid);if(!prod)return;const custId=document.getElementById('saleCust').value;const cust=db.customers.find(c=>c.id===custId);const paymentStatus=document.getElementById('salePaymentStatus').value;const paymentMethod=document.getElementById('salePaymentMethod').value;const partialAmount=parseFloat(document.getElementById('salePartialAmount').value)||0;generatePDFInvoice({productId:pid,qty:qty,date:document.getElementById('saleDate').value,customerId:custId,paymentStatus:paymentStatus,paymentMethod:paymentMethod,partialAmount:partialAmount},prod,cust);}
function addSale(){const pid=document.getElementById('saleProd').value;const q=parseInt(document.getElementById('saleQty').value);if(!pid||!q||q<1){showToast('Select product & qty!','error');return;}if(q>getStock(pid)){showToast(`❌ Not enough! Available: ${getStock(pid)}`,'error');return;}const db=getDB();const inv=getNextInvoiceNumber();const paymentStatus=document.getElementById('salePaymentStatus').value;const paymentMethod=document.getElementById('salePaymentMethod').value;const partialAmount=parseFloat(document.getElementById('salePartialAmount').value)||0;const sale={id:genId(),productId:pid,qty:q,date:document.getElementById('saleDate').value,customerId:document.getElementById('saleCust').value,user:currentUser.name,invoiceNo:inv,createdAt:new Date().toISOString(),paymentStatus:paymentStatus,paymentMethod:paymentMethod,partialAmount:partialAmount,totalAmount:q*(db.products.find(p=>p.id===pid)?.sellPrice||0)};db.sales.push(sale);saveDB(db);document.getElementById('saleQty').value='';renderSaleHistory();const prod=db.products.find(p=>p.id===pid);const cust=db.customers.find(c=>c.id===sale.customerId);showToast(`Sold! ${inv}`,'success');if(confirm('Generate PDF Invoice?')){generatePDFInvoice(sale,prod,cust);}}
function saveDraft(){const pid=document.getElementById('saleProd').value;const q=parseInt(document.getElementById('saleQty').value);if(!pid||!q)return;const db=getDB();const paymentStatus=document.getElementById('salePaymentStatus').value;const paymentMethod=document.getElementById('salePaymentMethod').value;const partialAmount=parseFloat(document.getElementById('salePartialAmount').value)||0;db.drafts.push({id:genId(),productId:pid,qty:q,date:document.getElementById('saleDate').value,customerId:document.getElementById('saleCust').value,user:currentUser.name,createdAt:new Date().toISOString(),status:'draft',paymentStatus:paymentStatus,paymentMethod:paymentMethod,partialAmount:partialAmount});saveDB(db);document.getElementById('saleQty').value='';showToast('Draft saved!','success');}
function renderSaleHistory(){const db=getDB();const el=document.getElementById('saleHistory');if(!el)return;const from=document.getElementById('saleFrom')?.value||'';const to=document.getElementById('saleTo')?.value||'';let data=[...db.sales].filter(s=>{if(from&&s.date<from)return false;if(to&&s.date>to)return false;return true;}).reverse();el.innerHTML=`<table><thead><tr><th>Date</th><th>Invoice</th><th>Product</th><th>Qty</th><th>Revenue</th><th>Profit</th><th>Customer</th><th>Status</th><th>Method</th><th>Act</th></tr></thead><tbody>${data.map(s=>{const pr=db.products.find(x=>x.id===s.productId);const cust=db.customers.find(x=>x.id===s.customerId);const rev=s.qty*(pr?.sellPrice||0);const cost=s.qty*(pr?.buyPrice||0);const statusBadge=s.paymentStatus==='Paid'?'<span class="badge badge-success">Paid</span>':s.paymentStatus==='Partial'?`<span class="badge badge-warning">Partial: ${fmtBDT(s.partialAmount||0)}</span>`:'<span class="badge badge-danger">Unpaid</span>';const methodBadge=s.paymentMethod?`<span class="badge badge-info">${s.paymentMethod}</span>`:'-';return`<tr><td>${fmtDate(s.date)}</td><td><small>${s.invoiceNo||'-'}</small></td><td><strong>${pr?.name||'?'}</strong>${s.isReturn?'<br><span class="badge badge-danger">RETURNED</span>':''}</td><td>${s.qty}</td><td>${fmtBDT(rev)}</td><td style="color:${rev-cost>=0?'var(--success)':'var(--danger)'}">${fmtBDT(rev-cost)}</td><td>${cust?.name||'Walk-in'}</td><td>${statusBadge}</td><td>${methodBadge}</td><td>${!s.isReturn?`<button class="btn btn-info btn-xs" onclick="genInvoiceFromHistory('${s.id}')">📄</button> <button class="btn btn-danger btn-xs" onclick="returnSale('${s.id}')">↩️</button>`:'<small>Returned</small>'}</td></tr>`;}).join('')||'<tr><td colspan="10">No sales.</td></tr>'}</tbody></table>`;}
function genInvoiceFromHistory(sid){const db=getDB();const s=db.sales.find(x=>x.id===sid);if(!s)return;const prod=db.products.find(p=>p.id===s.productId);const cust=db.customers.find(c=>c.id===s.customerId);generatePDFInvoice(s,prod,cust);}
function returnSale(sid){if(!confirm('Return?'))return;const r=prompt('Reason:');if(!r)return;const db=getDB();const s=db.sales.find(x=>x.id===sid);if(!s)return;s.isReturn=true;s.returnReason=r;s.returnedAt=new Date().toISOString();saveDB(db);renderSaleHistory();showToast('Returned.','success');}

// ==================== DRAFT INVOICES ====================
function renderDrafts(mc){const db=getDB();const drafts=db.drafts||[];mc.innerHTML=`<div class="page-header"><h2>📋 Draft Invoices</h2></div><div class="card"><div class="table-container"><table><thead><tr><th>Date</th><th>Product</th><th>Qty</th><th>Customer</th><th>Amount</th><th>Status</th><th>Method</th><th>Actions</th></tr></thead><tbody>${drafts.map(d=>{const pr=db.products.find(x=>x.id===d.productId);const cust=db.customers.find(x=>x.id===d.customerId);const statusBadge=d.paymentStatus==='Paid'?'<span class="badge badge-success">Paid</span>':d.paymentStatus==='Partial'?`<span class="badge badge-warning">Partial</span>`:'<span class="badge badge-danger">Unpaid</span>';const methodBadge=d.paymentMethod?`<span class="badge badge-info">${d.paymentMethod}</span>`:'-';return`<tr><td>${fmtDate(d.date)}</td><td><strong>${pr?.name||'?'}</strong></td><td>${d.qty}</td><td>${cust?.name||'Walk-in'}</td><td>${fmtBDT(d.qty*(pr?.sellPrice||0))}</td><td>${statusBadge}</td><td>${methodBadge}</td><td><button class="btn btn-success btn-xs" onclick="finalizeDraft('${d.id}')">✅</button> <button class="btn btn-info btn-xs" onclick="editDraft('${d.id}')">✏️</button> <button class="btn btn-danger btn-xs" onclick="deleteDraft('${d.id}')">🗑️</button> <button class="btn btn-primary btn-xs" onclick="printDraft('${d.id}')">🖨️</button></td></tr>`;}).join('')||'<tr><td colspan="8">No drafts.</td></tr>'}</tbody></table></div></div>`;}
function printDraft(did){const db=getDB();const d=db.drafts.find(x=>x.id===did);if(!d)return;const prod=db.products.find(p=>p.id===d.productId);const cust=db.customers.find(c=>c.id===d.customerId);generatePDFInvoice({productId:d.productId,qty:d.qty,date:d.date,customerId:d.customerId,paymentStatus:d.paymentStatus,paymentMethod:d.paymentMethod,partialAmount:d.partialAmount},prod,cust);}
function finalizeDraft(did){const db=getDB();const d=db.drafts.find(x=>x.id===did);if(!d)return;if(d.qty>getStock(d.productId)){showToast('Not enough stock!','error');return;}const inv=getNextInvoiceNumber();db.sales.push({id:genId(),productId:d.productId,qty:d.qty,date:d.date,customerId:d.customerId,user:currentUser.name,invoiceNo:inv,createdAt:new Date().toISOString(),paymentStatus:d.paymentStatus,paymentMethod:d.paymentMethod,partialAmount:d.partialAmount,totalAmount:d.qty*(db.products.find(p=>p.id===d.productId)?.sellPrice||0)});db.drafts=db.drafts.filter(x=>x.id!==did);saveDB(db);showToast(`Finalized! ${inv}`,'success');navigateTo('sale');}
function editDraft(did){const db=getDB();const d=db.drafts.find(x=>x.id===did);if(!d)return;db.drafts=db.drafts.filter(x=>x.id!==did);saveDB(db);navigateTo('sale');setTimeout(()=>{document.getElementById('saleProd').value=d.productId;document.getElementById('saleQty').value=d.qty;document.getElementById('saleDate').value=d.date;if(d.customerId)document.getElementById('saleCust').value=d.customerId;document.getElementById('salePaymentStatus').value=d.paymentStatus||'Paid';document.getElementById('salePaymentMethod').value=d.paymentMethod||'Cash';if(d.partialAmount)document.getElementById('salePartialAmount').value=d.partialAmount;showToast('Draft loaded!','info');},300);}
function deleteDraft(did){if(!confirm('Delete?'))return;const db=getDB();db.drafts=db.drafts.filter(x=>x.id!==did);saveDB(db);renderDrafts(document.getElementById('mainContent'));showToast('Deleted.','warning');}

// ==================== PDF INVOICE GENERATION (with payment method) ====================
function generatePDFInvoice(sale,prod,cust){const b=getBranding();const total=sale.qty*(prod?.sellPrice||0);const paidAmount=sale.paymentStatus==='Paid'?total:(sale.paymentStatus==='Partial'?(sale.partialAmount||0):0);const dueAmount=total-paidAmount;const date=new Date(sale.date);const inv=sale.invoiceNo||getNextInvoiceNumber();const paymentStatusText=sale.paymentStatus==='Paid'?'✅ PAID':sale.paymentStatus==='Partial'?`⚠️ PARTIAL (Paid: ${fmtBDT(paidAmount)})`:'❌ UNPAID';const paymentMethodText=sale.paymentMethod?`Method: ${sale.paymentMethod}`:'Cash';const h=`<!DOCTYPE html><html><head><meta charset="UTF-8"><link href="https://fonts.googleapis.com/css2?family=DM+Serif+Display&family=DM+Sans:wght@300;400;500;600;700&family=JetBrains+Mono:wght@400;600&display=swap" rel="stylesheet"><style>*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}:root{--navy:#0f2a4a;--blue:#1a56a0;--red:#c0392b;--green:#16a34a;--gray-900:#1a1a2e;--gray-700:#374151;--gray-500:#6b7280;--gray-300:#d1d5db;--gray-100:#f3f6fb}body{font-family:'DM Sans',sans-serif;background:#fff;color:var(--gray-700);font-size:13px}.wrap{max-width:210mm;margin:0 auto}.banner{background:var(--navy);padding:28px 40px;display:flex;justify-content:space-between;position:relative;overflow:hidden}.banner::before{content:'';position:absolute;inset:0;background:radial-gradient(ellipse 60% 140% at 110% 50%,rgba(26,86,160,.45),transparent 70%)}.bn{font-family:'DM Serif Display',serif;font-size:1.8rem;color:#fff;position:relative}.bt{font-size:.7rem;color:rgba(255,255,255,.5);letter-spacing:.12em;text-transform:uppercase;position:relative}.il{font-family:'JetBrains Mono',monospace;font-size:.6rem;letter-spacing:.18em;color:#f0a500;text-align:right;position:relative}.inum{font-family:'JetBrains Mono',monospace;font-size:1.3rem;font-weight:600;color:#fff;text-align:right;position:relative}.sb{background:var(--gray-100);padding:8px 40px;display:flex;gap:20px;border-bottom:1px solid var(--gray-300)}.body{padding:28px 40px}.ig{display:grid;grid-template-columns:1fr 1fr 1fr;border:1px solid var(--gray-300);border-radius:10px;overflow:hidden;margin-bottom:24px}.ib{padding:16px 20px;border-right:1px solid var(--gray-300)}.ib:last-child{border-right:none}.ibl{font-size:.6rem;font-weight:700;letter-spacing:.15em;text-transform:uppercase;color:var(--blue);margin-bottom:8px}.it{width:100%;border-collapse:separate;border-spacing:0;border:1px solid var(--gray-300);border-radius:10px;overflow:hidden;margin-bottom:16px}.it thead tr{background:var(--navy);color:#fff}.it th{padding:10px 16px;font-size:.65rem;font-weight:600;text-transform:uppercase}.it td{padding:11px 16px;border-top:1px solid var(--gray-100)}.tw{display:flex;justify-content:flex-end;margin-bottom:24px}.tot{min-width:260px;border:1px solid var(--gray-300);border-radius:10px;overflow:hidden}.tr{display:flex;justify-content:space-between;padding:9px 18px;font-size:.82rem;border-bottom:1px solid var(--gray-300)}.tr.grand{background:var(--navy);padding:12px 18px}.tr.grand span{color:#fff!important;font-weight:700}.payment-status{background:${sale.paymentStatus==='Paid'?'var(--green)':sale.paymentStatus==='Partial'?'var(--red)':'var(--red)'};color:white;padding:8px 15px;border-radius:8px;font-weight:bold;display:inline-block}.fg{display:grid;grid-template-columns:1fr 1fr;gap:20px;padding-top:20px;border-top:1px solid var(--gray-300);margin-bottom:24px}.thx{text-align:center;padding-top:16px;font-family:'DM Serif Display',serif;font-size:1.1rem;color:var(--navy)}@media print{body{background:#fff;-webkit-print-color-adjust:exact;print-color-adjust:exact}@page{margin:0;size:A4}}</style></head><body><div class="wrap"><div class="banner"><div><div class="bn">${b.companyName}</div><div class="bt">${b.tagline}</div></div><div><div class="il">Invoice</div><div class="inum">${inv}</div></div></div><div class="sb"><span>Issued: <strong>${date.toLocaleDateString('en-IN',{day:'2-digit',month:'long',year:'numeric'})}</strong></span><span>Status: <strong class="payment-status">${paymentStatusText}</strong></span><span>Payment: <strong>${paymentMethodText}</strong></span></div><div class="body"><div class="ig"><div class="ib"><div class="ibl">From</div><p><strong>${b.companyName}</strong></p>${b.address?`<p>${b.address}</p>`:''}${b.phone?`<p>📞 ${b.phone}</p>`:''}</div><div class="ib"><div class="ibl">Bill To</div><p><strong>${cust?.name||'Walk-in Customer'}</strong></p>${cust?.phone?`<p>📞 ${cust.phone}</p>`:''}</div><div class="ib"><div class="ibl">Details</div><p>Invoice: ${inv}</p><p>Issued: ${date.toLocaleDateString('en-IN',{day:'2-digit',month:'short',year:'numeric'})}</p><p>Served: ${currentUser?.name||sale.user||'Staff'}</p></div></div><table class="it"><thead><tr><th>Description</th><th style="text-align:center">Qty</th><th style="text-align:right">Price</th><th style="text-align:right">Total</th></tr></thead><tbody><tr><td>${prod?.name||'Product'} <span style="font-size:.64rem;background:#d6e4f7;color:var(--blue);padding:1px 6px;border-radius:99px;">${prod?.unit||'pcs'}</span></td><td style="text-align:center">${sale.qty}</td><td style="text-align:right">${fmtBDT(prod?.sellPrice||0)}</td><td style="text-align:right;font-weight:600">${fmtBDT(total)}</td></tr></tbody></table><div class="tw"><div class="tot"><div class="tr"><span>Subtotal</span><span>${fmtBDT(total)}</span></div>${sale.paymentStatus!=='Paid'?`<div class="tr"><span>Paid</span><span>${fmtBDT(paidAmount)}</span></div><div class="tr grand"><span>Due Amount</span><span>${fmtBDT(dueAmount)}</span></div>`:`<div class="tr grand"><span>Total Paid</span><span>${fmtBDT(total)}</span></div>`}</div></div><div class="fg"><div><div class="ibl">Payment</div>${b.bankName?`<p>Bank: ${b.bankName}</p><p>A/C: ${b.companyName}</p><p>No: ${b.bankAccount||'N/A'}</p>`:'<p>Cash/Transfer</p>'}<p>Method: ${paymentMethodText}</p></div><div><div class="ibl">Terms</div><p>${sale.paymentStatus==='Unpaid'?'Payment due within 30 days.':'Thank you for your payment!'}</p><p>Computer-generated invoice.</p></div></div><div class="thx">🙏 Thank You!</div></div></div></body></html>`;html2pdf().set({margin:[0,0,0,0],filename:`Invoice_${inv.replace('/','-')}.pdf`,image:{type:'jpeg',quality:1},html2canvas:{scale:2,useCORS:true,backgroundColor:'#ffffff'},jsPDF:{unit:'mm',format:'a4',orientation:'portrait'}}).from(h).save().then(()=>showToast('📄 Invoice downloaded!','success')).catch(err=>showToast('PDF Error: '+err,'error'));}

// ==================== EXPENSES ====================
function renderExpenses(mc){const db=getDB();const ex=db.expenses||[];const te=ex.reduce((s,e)=>s+(parseFloat(e.amount)||0),0);mc.innerHTML=`<div class="page-header"><h2>💸 Expenses</h2></div><div class="card"><h3>➕ Record</h3><div class="form-grid"><div class="form-group"><label>Category</label><select id="ec"><option value="">-- Choose --</option><option>Rent</option><option>Electricity</option><option>Salary</option><option>Office Supplies</option><option>Transport</option><option>Marketing</option><option>Maintenance</option><option>Other</option></select></div><div class="form-group"><label>Amount *</label><input type="number" id="ea" step="0.01"></div><div class="form-group"><label>Date</label><input type="date" id="ed" value="${new Date().toISOString().split('T')[0]}"></div><div class="form-group"><label>Description</label><input type="text" id="eds" placeholder="Optional notes..."></div></div><button class="btn btn-warning" onclick="addExpense()">💸 Record</button></div><div class="card"><h3>History (Total: ${fmtBDT(te)})</h3><div class="table-container"><table><thead><tr><th>Date</th><th>Category</th><th>Amount</th><th>Description</th><th>Actions</th></tr></thead><tbody>${[...ex].reverse().map(e=>`<tr><td>${fmtDate(e.date)}</td><td>${e.category}</td><td>${fmtBDT(e.amount)}</td><td>${e.description||'-'}</td><td><button class="btn btn-info btn-xs" onclick="editExpense('${e.id}')">✏️</button> <button class="btn btn-danger btn-xs" onclick="deleteExpense('${e.id}')">🗑️</button></td></tr>`).join('')}</tbody></table></div></div>`;}
function addExpense(){const c=document.getElementById('ec').value;const a=parseFloat(document.getElementById('ea').value);if(!c||isNaN(a)){showToast('Fill category & amount!','error');return;}const db=getDB();db.expenses.push({id:genId(),category:c,amount:a,date:document.getElementById('ed').value,description:document.getElementById('eds').value,user:currentUser.name});saveDB(db);renderExpenses(document.getElementById('mainContent'));showToast('Recorded!','success');}
function editExpense(eid){const db=getDB();const e=db.expenses.find(x=>x.id===eid);if(!e)return;const na=parseFloat(prompt('New amount:',e.amount));if(isNaN(na))return;e.amount=na;const nd=prompt('New description:',e.description||'');if(nd!==null)e.description=nd;saveDB(db);renderExpenses(document.getElementById('mainContent'));showToast('Updated!','success');}
function deleteExpense(eid){if(!confirm('Delete?'))return;const db=getDB();db.expenses=db.expenses.filter(e=>e.id!==eid);saveDB(db);renderExpenses(document.getElementById('mainContent'));showToast('Deleted.','warning');}

// ==================== CREDIT SALES ====================
function renderCreditSales(mc){const db=getDB();const cs=db.creditSales||[];const pending=cs.filter(c=>c.status==='pending');const td=pending.reduce((s,c)=>s+(parseFloat(c.dueAmount)||0),0);mc.innerHTML=`<div class="page-header"><h2>📋 Credit/Due Sales</h2><button class="btn btn-primary" onclick="document.getElementById('csForm').style.display='block'">➕ New</button></div><div class="card" id="csForm" style="display:none;"><h3>➕ New</h3><div class="form-grid"><div class="form-group"><label>Customer *</label><select id="csCust">${(db.customers||[]).map(c=>`<option value="${c.id}">${c.name}${c.phone?' - '+c.phone:''}</option>`).join('')}</select></div><div class="form-group"><label>Product *</label><select id="csProd">${db.products.map(p=>`<option value="${p.id}">${p.name}</option>`).join('')}</select></div><div class="form-group"><label>Qty *</label><input type="number" id="csQty" min="1"></div><div class="form-group"><label>Total (৳)</label><input type="number" id="csTotal" step="0.01"></div><div class="form-group"><label>Paid (৳)</label><input type="number" id="csPaid" step="0.01" value="0"></div><div class="form-group"><label>Date</label><input type="date" id="csDate" value="${new Date().toISOString().split('T')[0]}"></div></div><button class="btn btn-primary" onclick="addCreditSale()">💾 Save</button></div><div class="card"><h3>Pending (Due: ${fmtBDT(td)})</h3><div class="table-container"><table><thead><tr><th>Date</th><th>Customer</th><th>Total</th><th>Paid</th><th>Due</th><th>Actions</th></tr></thead><tbody>${pending.map(c=>{const cust=db.customers.find(x=>x.id===c.customerId);return`<tr><td>${fmtDate(c.date)}</td><td>${cust?.name||'?'}</td><td>${fmtBDT(c.totalAmount)}</td><td>${fmtBDT(c.paidAmount)}</td><td><span class="badge badge-danger">${fmtBDT(c.dueAmount)}</span></td><td><button class="btn btn-success btn-xs" onclick="addPayment('${c.id}')">💵</button> <button class="btn btn-info btn-xs" onclick="printCreditInvoice('${c.id}')">🖨️</button></td></tr>`;}).join('')||'<tr><td colspan="6">✅ No dues!</td></tr>'}</tbody></table></div></div>`;}
function printCreditInvoice(csid){const db=getDB();const cs=db.creditSales.find(x=>x.id===csid);if(!cs)return;const prod=db.products.find(p=>p.id===cs.productId);const cust=db.customers.find(c=>c.id===cs.customerId);generatePDFInvoice({productId:cs.productId,qty:cs.qty,date:cs.date,customerId:cs.customerId,invoiceNo:'CREDIT-'+cs.id.slice(-6),paymentStatus:cs.dueAmount<=0?'Paid':'Unpaid',paymentMethod:'Credit',partialAmount:cs.paidAmount},prod,cust);}
function addCreditSale(){const cid=document.getElementById('csCust').value;const pid=document.getElementById('csProd').value;const qty=parseInt(document.getElementById('csQty').value);const total=parseFloat(document.getElementById('csTotal').value);const paid=parseFloat(document.getElementById('csPaid').value)||0;if(!cid||!pid||!qty||isNaN(total))return;const db=getDB();db.creditSales.push({id:genId(),customerId:cid,productId:pid,qty,totalAmount:total,paidAmount:paid,dueAmount:total-paid,date:document.getElementById('csDate').value,status:total-paid<=0?'paid':'pending',createdAt:new Date().toISOString()});saveDB(db);document.getElementById('csForm').style.display='none';renderCreditSales(document.getElementById('mainContent'));showToast('Recorded!','success');}
function addPayment(csid){const a=parseFloat(prompt('Payment:'));if(isNaN(a)||a<=0)return;const db=getDB();const cs=db.creditSales.find(x=>x.id===csid);if(!cs)return;cs.paidAmount+=a;cs.dueAmount=cs.totalAmount-cs.paidAmount;if(cs.dueAmount<=0){cs.status='paid';cs.dueAmount=0;}saveDB(db);renderCreditSales(document.getElementById('mainContent'));showToast('Paid!','success');}

// ==================== REPORTS (top/slow fixed) ====================
function renderCashBook(mc){const db=getDB();const t=new Date().toISOString().split('T')[0];const sr=db.sales.filter(s=>s.date===t&&!s.isReturn).reduce((s,x)=>{const p=db.products.find(p=>p.id===x.productId);return s+(x.qty*(p?.sellPrice||0));},0);const pr=db.purchases.filter(p=>p.date===t).reduce((s,p)=>{const x=db.products.find(x=>x.id===p.productId);return s+(p.qty*(x?.buyPrice||0));},0);const ex=db.expenses.filter(e=>e.date===t).reduce((s,e)=>s+(parseFloat(e.amount)||0),0);mc.innerHTML=`<div class="page-header"><h2>📒 Daily Cash Book</h2></div><div class="stats-grid"><div class="stat-card success"><div class="stat-value">${fmtBDT(sr)}</div><div class="stat-label">Sales</div></div><div class="stat-card warning"><div class="stat-value">${fmtBDT(pr)}</div><div class="stat-label">Purchases</div></div><div class="stat-card danger"><div class="stat-value">${fmtBDT(ex)}</div><div class="stat-label">Expenses</div></div><div class="stat-card ${sr-pr-ex>=0?'success':'danger'}"><div class="stat-value">${fmtBDT(sr-pr-ex)}</div><div class="stat-label">Net Cash</div></div></div>`;}
function renderStock(mc){const db=getDB();let t=0;mc.innerHTML=`<div class="page-header"><h2>📋 Stock Report</h2><button class="btn btn-info" onclick="window.print()">🖨️ Print Page</button></div><div class="card"><table><thead><tr><th>Product</th><th>Stock</th><th>Value</th></tr></thead><tbody>${db.products.map(p=>{const s=getStock(p.id);const v=s*(p.buyPrice||0);t+=v;return`<tr><td>${p.name}</td><td>${s}</td><td>${fmtBDT(v)}</td></tr>`;}).join('')}<tr><td colspan="2"><strong>Total</strong></td><td><strong>${fmtBDT(t)}</strong></td></tr></tbody></table></div>`;}
function renderProfit(mc){const db=getDB();let tr=0,tc=0;db.products.forEach(p=>{const s=db.sales.filter(s=>s.productId===p.id&&!s.isReturn).reduce((s,x)=>s+x.qty,0);tr+=s*(p.sellPrice||0);tc+=s*(p.buyPrice||0);});const te=(db.expenses||[]).reduce((s,e)=>s+(parseFloat(e.amount)||0),0);mc.innerHTML=`<div class="page-header"><h2>💰 Profit & Loss</h2></div><div class="stats-grid"><div class="stat-card success"><div class="stat-value">${fmtBDT(tr)}</div><div class="stat-label">Revenue</div></div><div class="stat-card warning"><div class="stat-value">${fmtBDT(tc)}</div><div class="stat-label">COGS</div></div><div class="stat-card danger"><div class="stat-value">${fmtBDT(te)}</div><div class="stat-label">Expenses</div></div><div class="stat-card ${tr-tc-te>=0?'primary':'danger'}"><div class="stat-value">${fmtBDT(tr-tc-te)}</div><div class="stat-label">Net Profit</div></div></div>`;}
function renderInventoryAging(mc){const db=getDB();const now=new Date();const a=[];db.products.forEach(p=>{const ls=db.sales.filter(s=>s.productId===p.id&&!s.isReturn).sort((a,b)=>new Date(b.date)-new Date(a.date))[0];const d=ls?Math.floor((now-new Date(ls.date))/86400000):999;const s=getStock(p.id);if(s>0)a.push({name:p.name,stock:s,days:d});});mc.innerHTML=`<div class="page-header"><h2>📅 Inventory Aging</h2></div><div class="card"><div class="table-container"><table><thead><tr><th>Product</th><th>Stock</th><th>Days Since Last Sale</th><th>Status</th></tr></thead><tbody>${a.map(x=>`<tr><td>${x.name}</td><td>${x.stock}</td><td>${x.days===999?'Never Sold':x.days}</td><td><span class="badge ${x.days>=90?'badge-danger':x.days>=30?'badge-warning':'badge-success'}">${x.days>=90?'Dead Stock':x.days>=30?'Slow Moving':'Active'}</span></td></tr>`).join('')||'<tr><td colspan="4">No products with stock.</td></tr>'}</tbody></table></div></div>`;}
function renderTopProducts(mc){const db=getDB();const ps=db.products.map(p=>{const s=db.sales.filter(s=>s.productId===p.id&&!s.isReturn).reduce((s,x)=>s+x.qty,0);return{...p,sold:s};}).sort((a,b)=>b.sold-a.sold);mc.innerHTML=`<div class="page-header"><h2>🏆 Top & Slow Products</h2><button class="btn btn-info" onclick="window.print()">🖨️ Print Page</button></div><div class="card"><h3>Top 5 Best Sellers</h3><div class="table-container"><table><thead><tr><th>#</th><th>Product Name</th><th>Quantity Sold</th></tr></thead><tbody>${ps.slice(0,5).map((p,i)=>`<tr><td>${i+1}</td><td>${p.name}</td><td>${p.sold}</td></tr>`).join('')}</tbody></table></div></div><div class="card"><h3>Slow Moving / Zero Sales (with stock)</h3><div class="table-container"><table><thead><tr><th>Product Name</th><th>Current Stock</th></tr></thead><tbody>${ps.filter(p=>p.sold===0&&getStock(p.id)>0).slice(0,10).map(p=>`<tr><td>${p.name}</td><td>${getStock(p.id)}</td></tr>`).join('')||'<tr><td colspan="2">✅ All products have been sold!</td></tr>'}</tbody></table></div></div>`;}
function renderExpiry(mc){const db=getDB();const now=new Date();const s=[];db.products.forEach(p=>{if(p.expiryDate){const d=Math.ceil((new Date(p.expiryDate)-now)/86400000);if(d<=30&&getStock(p.id)>0)s.push({name:p.name,days:d,expiryDate:p.expiryDate});}});mc.innerHTML=`<div class="page-header"><h2>⏰ Expiry Tracker</h2></div><div class="card"><div class="table-container"><table><thead><tr><th>Product</th><th>Expiry Date</th><th>Days Left</th><th>Status</th></tr></thead><tbody>${s.sort((a,b)=>a.days-b.days).map(p=>`<tr><td>${p.name}</td><td>${fmtDate(p.expiryDate)}</td><td>${p.days}</td><td><span class="badge ${p.days<=7?'badge-danger':'badge-warning'}">${p.days<=7?'Critical':'Warning'}</span></td></tr>`).join('')||'<tr><td colspan="4">✅ No products expiring soon!</td></tr>'}</tbody></table></div></div>`;}

// ==================== BRANDING ====================
function renderBranding(mc){const b=getBranding();mc.innerHTML=`<div class="page-header"><h2>🎨 Branding</h2></div><div class="card"><h3>🏢 Company</h3><div class="form-grid"><div class="form-group"><label>Name</label><input type="text" id="bName" value="${b.companyName}"></div><div class="form-group"><label>Tagline</label><input type="text" id="bTagline" value="${b.tagline}"></div><div class="form-group"><label>Owner</label><input type="text" id="bOwner" value="${b.owner||''}"></div><div class="form-group"><label>Phone</label><input type="text" id="bPhone" value="${b.phone||''}"></div><div class="form-group"><label>Email</label><input type="email" id="bEmail" value="${b.email||''}"></div><div class="form-group"><label>Website</label><input type="text" id="bWebsite" value="${b.website||''}"></div><div class="form-group"><label>Address</label><textarea id="bAddress">${b.address||''}</textarea></div></div></div><div class="card"><h3>🏦 Bank</h3><div class="form-grid"><div class="form-group"><label>Bank Name</label><input type="text" id="bBankName" value="${b.bankName||''}"></div><div class="form-group"><label>Account No</label><input type="text" id="bBankAccount" value="${b.bankAccount||''}"></div><div class="form-group"><label>Branch</label><input type="text" id="bBankBranch" value="${b.bankBranch||''}"></div><div class="form-group"><label>Routing</label><input type="text" id="bBankRouting" value="${b.bankRouting||''}"></div></div></div><div class="card"><h3>🖼️ Logo</h3><div class="photo-upload-area" onclick="document.getElementById('logoInput').click()" style="width:150px;height:150px;"><span id="logoPlaceholder">🏢 Upload</span><img id="logoPreviewImg" style="display:none;max-width:130px;"><input type="file" id="logoInput" accept="image/*" style="display:none;" onchange="handleLogoUpload(event)"></div><button class="btn btn-danger btn-sm" id="removeLogoBtn" style="display:none;" onclick="removeLogo()">🗑️</button></div><div class="card"><h3>🎨 Theme</h3><div class="color-presets">${['#4f46e5','#059669','#dc2626','#d97706','#0891b2','#7c3aed','#be185d','#1e293b'].map(c=>`<div class="color-preset${b.themeColor===c?' active':''}" style="background:${c};" onclick="changeThemeColor('${c}',this)"></div>`).join('')}</div></div><button class="btn btn-primary" onclick="saveBrandingFromPage()">💾 Save All</button>`;if(b.logo){document.getElementById('logoPreviewImg').src=b.logo;document.getElementById('logoPreviewImg').style.display='block';document.getElementById('logoPlaceholder').style.display='none';document.getElementById('removeLogoBtn').style.display='block';}}
function handleLogoUpload(e){const f=e.target.files[0];if(!f)return;const r=new FileReader();r.onload=ev=>{const d=ev.target.result;document.getElementById('logoPreviewImg').src=d;document.getElementById('logoPreviewImg').style.display='block';document.getElementById('logoPlaceholder').style.display='none';document.getElementById('removeLogoBtn').style.display='block';const b=getBranding();b.logo=d;saveBranding(b);};r.readAsDataURL(f);}
function removeLogo(){document.getElementById('logoPreviewImg').style.display='none';document.getElementById('logoPlaceholder').style.display='block';document.getElementById('removeLogoBtn').style.display='none';const b=getBranding();b.logo=null;saveBranding(b);}
function changeThemeColor(c,el){document.documentElement.style.setProperty('--primary',c);document.querySelectorAll('.color-preset').forEach(p=>p.classList.remove('active'));if(el)el.classList.add('active');const b=getBranding();b.themeColor=c;saveBranding(b);}
function saveBrandingFromPage(){const b=getBranding();b.companyName=document.getElementById('bName').value||'WishMe Enterprise';b.tagline=document.getElementById('bTagline').value||'Suite';b.owner=document.getElementById('bOwner').value;b.phone=document.getElementById('bPhone').value;b.email=document.getElementById('bEmail').value;b.website=document.getElementById('bWebsite').value;b.address=document.getElementById('bAddress').value;b.bankName=document.getElementById('bBankName').value;b.bankAccount=document.getElementById('bBankAccount').value;b.bankBranch=document.getElementById('bBankBranch').value;b.bankRouting=document.getElementById('bBankRouting').value;saveBranding(b);showToast('Branding saved!','success');setTimeout(()=>{applyBranding(getBranding());navigateTo('dashboard');},300);}

// ==================== USERS ====================
function renderUsers(mc){const u=getUsers();let r='';Object.entries(u).forEach(([k,v])=>{r+=`<tr><td><strong>${v.name}</strong></td><td>${v.role}</td><td><button class="btn btn-info btn-xs" onclick="editUser('${k}')">✏️</button>${k!=='admin'?` <button class="btn btn-danger btn-xs" onclick="deleteUser('${k}')">🗑️</button>`:''}</td></tr>`;});mc.innerHTML=`<div class="page-header"><h2>👥 Users</h2></div><div class="card" id="userFormCard" style="display:none;"><h3>✏️ Edit</h3><div class="form-grid"><div class="form-group"><label>Name</label><input type="text" id="editUserName"></div><div class="form-group"><label>Password</label><input type="password" id="editUserPass"></div><div class="form-group"><label>Role</label><select id="editUserRole"><option>staff</option><option>admin</option></select></div></div><input type="hidden" id="editUserKey"><button class="btn btn-primary" onclick="saveUserEdit()">💾 Save</button><button class="btn btn-ghost btn-sm" onclick="document.getElementById('userFormCard').style.display='none'">❌</button></div><div class="card"><h3>➕ Add</h3><div class="form-grid"><div class="form-group"><label>Key</label><input type="text" id="newUserKey"></div><div class="form-group"><label>Name</label><input type="text" id="newUserName"></div><div class="form-group"><label>Password</label><input type="password" id="newUserPass"></div><div class="form-group"><label>Role</label><select id="newUserRole"><option>staff</option><option>admin</option></select></div></div><button class="btn btn-primary" onclick="addUser()">➕ Create</button></div><div class="card"><h3>Users</h3><div class="table-container"><table><thead><tr><th>Name</th><th>Role</th><th>Actions</th></tr></thead><tbody>${r}</tbody></table></div></div>`;}
function editUser(k){const u=getUsers()[k];if(!u)return;document.getElementById('userFormCard').style.display='block';document.getElementById('editUserName').value=u.name;document.getElementById('editUserRole').value=u.role;document.getElementById('editUserKey').value=k;}
function saveUserEdit(){const k=document.getElementById('editUserKey').value;const n=document.getElementById('editUserName').value.trim();const p=document.getElementById('editUserPass').value;const rl=document.getElementById('editUserRole').value;if(!n)return;const u=getUsers();u[k].name=n;u[k].role=rl;if(p&&p.length>=6)u[k].pass=p;saveUsers(u);document.getElementById('userFormCard').style.display='none';renderUsers(document.getElementById('mainContent'));if(currentUser.key===k){currentUser.name=n;document.getElementById('currentUserName').textContent=n;}showToast('Updated!','success');}
function addUser(){const k=document.getElementById('newUserKey').value.trim();const n=document.getElementById('newUserName').value.trim();const p=document.getElementById('newUserPass').value;const rl=document.getElementById('newUserRole').value;if(!k||!n||!p||p.length<6)return;const u=getUsers();if(u[k])return;u[k]={name:n,role:rl,pass:p,createdAt:new Date().toISOString()};saveUsers(u);renderUsers(document.getElementById('mainContent'));showToast('Created!','success');}
function deleteUser(k){if(k==='admin')return;if(!confirm('Delete?'))return;const u=getUsers();delete u[k];saveUsers(u);renderUsers(document.getElementById('mainContent'));showToast('Deleted.','warning');}

// ==================== SETTINGS ====================
function renderSettings(mc){const cs=parseInt(localStorage.getItem('invoice_serial')||'0');mc.innerHTML=`<div class="page-header"><h2>⚙️ Settings</h2></div><div class="card"><h3>📋 Invoice Numbering</h3><p>Next: <strong>${getNextInvoiceNumber()}</strong></p><div class="form-grid"><div class="form-group"><label>Prefix</label><input type="text" id="invPrefix" value="${localStorage.getItem('invoice_prefix')||'INV'}"></div><div class="form-group"><label>Serial</label><input type="number" id="invSerial" value="${cs+1}"></div><div class="form-group"><label>Year</label><select id="invYear"><option value="true" ${localStorage.getItem('invoice_use_year')!=='false'?'selected':''}>Yes</option><option value="false">No</option></select></div></div><button class="btn btn-primary" onclick="saveInvoiceSettings()">💾 Save</button></div><div class="card"><button class="btn btn-danger" onclick="clearAllData()">🗑️ Delete All</button></div>`;}
function saveInvoiceSettings(){const p=document.getElementById('invPrefix').value.trim()||'INV';const s=parseInt(document.getElementById('invSerial').value);if(s>0)localStorage.setItem('invoice_serial',(s-1).toString());localStorage.setItem('invoice_prefix',p);localStorage.setItem('invoice_use_year',document.getElementById('invYear').value);showToast('Saved!','success');renderSettings(document.getElementById('mainContent'));}
function clearAllData(){if(prompt('Type DELETE:')!=='DELETE')return;localStorage.removeItem(DB_KEY);localStorage.removeItem(BRANDING_KEY);localStorage.removeItem(USER_STORAGE_KEY);location.reload();}

// ==================== BACKUP & GOOGLE DRIVE ====================
function renderStorageSettings(mc){const lb=localStorage.getItem('last_backup_time')||'Never';const bc=parseInt(localStorage.getItem('backup_count')||'0');mc.innerHTML=`<div class="page-header"><h2>📁 Backup & Google Drive</h2></div><div class="info-box"><strong>💡 How to keep your data safe:</strong><br>1. Click <strong>"Download Backup"</strong> below<br>2. Go to <a href="https://drive.google.com" target="_blank" style="color:var(--primary);">drive.google.com</a><br>3. Upload the downloaded file to your Google Drive<br>4. Set a reminder to backup <strong>daily or weekly</strong></div><div class="card"><h3>💾 Download Backup File</h3><p style="font-size:0.85rem;color:var(--text-light);margin-bottom:12px;">Downloads a complete backup of all your data including products, sales, customers, and photos.</p><div style="display:flex;gap:10px;flex-wrap:wrap;"><button class="btn btn-primary" onclick="downloadBackup()">📥 Download Backup (.json)</button><button class="btn btn-outline" onclick="downloadBackupCSV()">📥 Export Products (.csv)</button></div><div style="margin-top:8px;font-size:0.75rem;color:var(--text-muted);">Last backup: <strong>${lb}</strong> | Total backups: <strong>${bc}</strong></div></div><div class="card"><h3>📤 Quick Share to Google Drive</h3><p style="font-size:0.85rem;color:var(--text-light);margin-bottom:12px;">Opens Google Drive in a new tab. Drag & drop the downloaded file there.</p><button class="btn btn-info" onclick="window.open('https://drive.google.com/drive/my-drive','_blank')">📂 Open Google Drive</button></div><div class="card"><h3>📱 Share Backup via WhatsApp/Email</h3><div class="form-grid"><div class="form-group"><label>Method</label><select id="sm"><option value="whatsapp">📱 WhatsApp</option><option value="email">📧 Email</option></select></div><div class="form-group"><label>Target</label><input type="text" id="st" placeholder="Phone number or email"></div></div><button class="btn btn-info" onclick="shareBackup()" style="margin-top:10px;">📤 Share Backup</button></div><div class="card"><h3>📥 Restore from Backup</h3><p style="font-size:0.85rem;color:var(--text-light);margin-bottom:12px;">Restore data from a previously saved backup file.</p><button class="btn btn-outline" onclick="document.getElementById('rf').click()">📂 Select Backup File</button><input type="file" id="rf" accept=".json,.csv" style="display:none;" onchange="restoreFromFile(event)"><div id="restoreStatus" style="margin-top:10px;"></div></div><div class="card"><h3>⏰ Auto-Backup Reminder</h3><p style="font-size:0.85rem;color:var(--text-light);margin-bottom:12px;">Set how often you want to be reminded to backup.</p><select id="reminderInterval" onchange="setReminderInterval()"><option value="0">No reminder</option><option value="daily">Remind me daily</option><option value="weekly">Remind me weekly</option><option value="monthly">Remind me monthly</option></select><p style="font-size:0.7rem;color:var(--text-muted);margin-top:4px;">A toast notification will appear to remind you.</p></div><div class="card"><h3>🖥️ Auto-Backup Server (Option B)</h3><p style="font-size:0.85rem;color:var(--text-light);margin-bottom:12px;">If you have Node.js installed, run the backup server for automatic backups to a local folder.</p><button class="btn btn-outline" onclick="checkServerStatus()">🔍 Check Server Status</button><span id="serverStatus" style="margin-left:10px;font-size:0.85rem;"></span></div>`;document.getElementById('reminderInterval').value=localStorage.getItem('reminder_interval')||'0';}
function downloadBackup(){const db=getDB();const backupData={...db,branding:getBranding(),backupDate:new Date().toISOString()};let count=parseInt(localStorage.getItem('backup_count')||'0');localStorage.setItem('backup_count',(count+1).toString());localStorage.setItem('last_backup_time',new Date().toLocaleString('en-IN'));downloadFile(JSON.stringify(backupData,null,2),'WishMe_Backup_'+new Date().toISOString().split('T')[0]+'.json','application/json');showToast('Backup downloaded!','success');}
function downloadBackupCSV(){const db=getDB();let c='Product,Stock,Buy,Sell\n';db.products.forEach(p=>{c+=`"${p.name}",${getStock(p.id)},${p.buyPrice},${p.sellPrice}\n`;});downloadFile('\uFEFF'+c,'products.csv','text/csv');showToast('Exported!','success');}
function restoreFromFile(e){const f=e.target.files[0];if(!f)return;if(!confirm('⚠️ This will replace ALL current data! Continue?')){e.target.value='';return;}const r=new FileReader();r.onload=ev=>{try{const d=JSON.parse(ev.target.result);saveDB({products:d.products||[],purchases:d.purchases||[],sales:d.sales||[],expenses:d.expenses||[],customers:d.customers||[],suppliers:d.suppliers||[],creditSales:d.creditSales||[],drafts:d.drafts||[]});if(d.branding)saveBranding(d.branding);document.getElementById('restoreStatus').innerHTML='<span style="color:green;">✅ Restored successfully!</span>';showToast('Restored!','success');setTimeout(()=>{navigateTo('dashboard');},1000);}catch(ex){document.getElementById('restoreStatus').innerHTML='<span style="color:red;">❌ Invalid backup file!</span>';showToast('Invalid file!','error');}};r.readAsText(f);e.target.value='';}
function shareBackup(){const method=document.getElementById('sm').value;const target=document.getElementById('st').value.trim();if(!target){showToast('Enter phone number or email!','error');return;}downloadBackup();setTimeout(()=>{if(method==='whatsapp'){window.open(`https://wa.me/${target.replace(/[^0-9]/g,'')}?text=${encodeURIComponent('Here is my WishMe Enterprise backup file.')}`,'_blank');}else if(method==='email'){window.open(`mailto:${target}?subject=WishMe Enterprise Backup&body=I have attached my backup file.`,'_blank');}showToast('Share window opened!','info');},500);}
function setReminderInterval(){const val=document.getElementById('reminderInterval').value;localStorage.setItem('reminder_interval',val);if(val!=='0'){const reminderMsg={daily:'daily',weekly:'weekly',monthly:'monthly'};showToast(`✅ Reminder set: Backup ${reminderMsg[val]}!`,'success');}}
function checkServerStatus(){showToast('Server check: Use Node.js server for auto-backup feature.','info');document.getElementById('serverStatus').innerHTML='ℹ️ Not connected';}

function renderChangePassword(mc){mc.innerHTML=`<div class="page-header"><h2>🔐 Change Password</h2></div><div class="card"><div class="form-grid"><div class="form-group"><label>Current</label><input type="password" id="cpOld"></div><div class="form-group"><label>New</label><input type="password" id="cpNew"></div></div><button class="btn btn-primary" onclick="changePassword()">🔐 Update</button></div>`;}
function changePassword(){const u=getUsers();if(u[currentUser.key].pass!==document.getElementById('cpOld').value){showToast('Wrong!','error');return;}u[currentUser.key].pass=document.getElementById('cpNew').value;saveUsers(u);showToast('Changed!','success');}
function renderActivity(mc){const db=getDB();mc.innerHTML=`<div class="page-header"><h2>📝 My Activity</h2></div><div class="stats-grid"><div class="stat-card success"><div class="stat-value">${db.purchases.filter(p=>p.user===currentUser.name).length}</div><div class="stat-label">Purchases</div></div><div class="stat-card danger"><div class="stat-value">${db.sales.filter(s=>s.user===currentUser.name).length}</div><div class="stat-label">Sales</div></div></div>`;}

// ==================== INIT ====================
function init(){initTheme();ilb();updateLoginDropdown();applyBranding(getBranding());initFirebaseDB();document.getElementById('footer-year').textContent=new Date().getFullYear();updateStorageInfo();if(!checkExistingSession()){document.getElementById('loginScreen').style.display='flex';}}
init();